module BinaryToOneHot (
    input [1:0] invalid_bin,
    output [3:0] one_hot
);
    assign one_hot = (invalid_bin == 2'b00) ? 4'b0001 :
                     (invalid_bin == 2'b01) ? 4'b0010 :
                     (invalid_bin == 2'b10) ? 4'b0100 :
                                      4'b1000;
endmodule
